import re
import html as html_lib

_TAG_RE = re.compile(r"(?s)<[^>]*>")  # genel tag silici (en son aşama)
_SCRIPT_STYLE_RE = re.compile(r"(?is)<(script|style)\b[^>]*>.*?</\1>")
_COMMENT_RE = re.compile(r"(?s)<!--.*?-->")

def clean_html_regex(html: str, keep_newlines: bool = True) -> str:
    if not html:
        return ""

    s = html

    # 1) script/style bloklarını sil
    s = _SCRIPT_STYLE_RE.sub("", s)

    # 2) HTML yorumlarını sil
    s = _COMMENT_RE.sub("", s)

    # 3) Satır kırılması yaratmasını istediğin tag'leri newline'a çevir
    if keep_newlines:
        s = re.sub(r"(?i)<br\s*/?>", "\n", s)
        s = re.sub(r"(?i)</(p|div|li|tr|h[1-6])\s*>", "\n", s)
        s = re.sub(r"(?i)<li\b[^>]*>", "• ", s)  # list item başlangıcı

    # 4) Kalan tüm tag'leri sil
    s = _TAG_RE.sub("", s)

    # 5) HTML entity'leri çöz (&amp; -> &, &#39; -> ')
    s = html_lib.unescape(s)

    # 6) Whitespace normalize et
    s = re.sub(r"[ \t\r\f\v]+", " ", s)      # fazla boşlukları tek boşluk
    if keep_newlines:
        s = re.sub(r"\n\s*\n+", "\n", s)     # çoklu boş satırları azalt
        s = "\n".join(line.strip() for line in s.splitlines()).strip()
    else:
        s = re.sub(r"\s+", " ", s).strip()

    return s


